use std::collections::HashMap;

struct SecretScanner {
    history_data: HashMap<String, Vec<String>>
}

impl SecretScanner {
    fn new(data: HashMap<String, Vec<String>>) -> Self {
        SecretScanner { history_data: data }
    }

    fn process_ids<'a>(&'a self, ids: &'a [String]) -> impl Iterator<Item = Result<HashMap<String, String>, String>> + '_ {
        ids.iter().map(move |id| {
            if let Some(history) = self.history_data.get(id) {
                let mut result = HashMap::new();
                result.insert("id".to_string(), id.clone());
                let leaked_key: Option<String> = history.iter().find(|entry| entry.contains("SECRET_KEY:"))
                    .map(|entry| format!("Found key: {}", &entry[18..]));

                if let Some(key) = leaked_key {
                    result.insert("status".to_string(), "LEAKED".to_string());
                    result.insert("secret".to_string(), key);
                } else {
                    result.insert("status".to_string(), "CLEAN".to_string());
                    result.insert("secret".to_string(), "None found".to_string());
                }
                Ok(result)
            } else {
                Err(format!("No history data found for ID: {}", id))
            }
        })
    }
}

fn main() {
    let mut data = HashMap::new();
    data.insert("user1".to_string(), vec!["Commit 1: normal data".to_string(), "Commit 2: SECRET_KEY:abc123xyz".to_string()]);
    data.insert("user2".to_string(), vec!["Commit A: clean info".to_string()]);
    data.insert("user3".to_string(), vec!["Bad data format".to_string()]);

    let scanner = SecretScanner::new(data);
    let ids_to_check = vec!["user1".to_string(), "user2".to_string(), "nonexistent".to_string()];

    println!("n--- Starting Scan ---n");
    for result in scanner.process_ids(&ids_to_check) {
        match result {
            Ok(data) => println!("Processed ID {}: Status {}", data["id"].clone(), data["status"].clone()),
            Err(e) => println!("Error processing record: {}", e),
        }
    }
}

