use std::collections::HashMap;

struct Record {
    id: u32,
    data: String,
}

fn process_records(source_list: Vec<Record>) -> HashMap<u32, String> {
    let mut results = HashMap::new();
    for record in source_list.into_iter() {
        if record.id % 2 == 0 {
            results.insert(record.id, format!("Processed: {}", record.data));
        }
    }
    results
}

fn main() {
    let data = vec![ 
        Record { id: 1, data: "apple".to_string() }, 
        Record { id: 2, data: "banana".to_string() }, 
        Record { id: 3, data: "cherry".to_string() }, 
        Record { id: 4, data: "date".to_string() }, 
    ];

    let final_map = process_records(data);

    for (id, processed) in final_map {
        println!("Found ID: {}, Result: {}", id, processed);
    }
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct DataStreamer {
    reader: BufReader<File>,
}

impl DataStreamer {
    fn new(path: &str) -> io::Result<Self> {
        let file = File::open(path)?;
        Ok(DataStreamer { reader: BufReader::new(file) })
    }
}

impl Iterator for DataStreamer {
    type Item = String;

    fn next(&mut self) -> Option<Self::Item> {
        let mut buffer = Vec::new();
        match self.reader.read_until(b'n', &mut buffer) {
            Ok(0) => None,
            Ok(_) => Some(String::from_utf8_lossy(&buffer).to_string()),
            Err(_) => None,
        }
    }
}

fn main() -> io::Result<()> {
    use std::io::Write;
    let test_path = "test_data.txt";

    File::create(test_path)?.write_all(b"[HEADER]n")?;
    File::create(test_path)?.write_all(b"PlayerName=Kaelenn")?;
    File::create(test_path)?.write_all(b"QuestStatus=Activen")?;

    let mut streamer = DataStreamer::new(test_path)?;
    while let Some(line) = streamer.next() {
        println!("Processing chunk: {}", line);
    }
    Ok(())
}

use std::collections::HashSet;

struct DungeonMap {
    width: usize,
    height: usize,
    cells: Vec<Vec<bool>>
}

impl DungeonMap {
    fn new(width: usize, height: usize) -> Self {
        DungeonMap { width, height, cells: vec![vec![false; width]; height] }
    }

    fn is_valid(&self, x: usize, y: usize) -> bool {
        x < self.width && y < self.height
    }

    fn check_cell_status<F: Fn(usize, usize) -> bool>(&self, is_solid: F) -> Vec<(usize, usize)> {
        let mut found_coordinates = Vec::new();
        for y in 0..self.height
        {
            if !self.is_valid(0, y) {}
            for x in 0..self.width
            {
                if is_solid(x, y) {
                    found_coordinates.push((x, y));
                }
            }
        }
        found_coordinates
    }
}

fn main() {
    let map = DungeonMap::new(10, 5);

    let solid_check = |x: usize, y: usize| -> bool {
        if x == 2 && y == 3 || x == 7 && y == 1 {
            true
        } else {
            false
        }
    };

    let found = map.check_cell_status(solid_check);
    println!("Found {} solid spots.", found.len());
    if let Some(&(x, y)) = found.get(0) {
        println!("First spot checked: ({}, {}).", x, y);
    }
}
